LAYER
	NAME "comunidad_campesina"
	TYPE polygon
	STATUS on
	DATA "geom FROM (SELECT gid, nomcom, depar, provi, distr, ubidis, codigo :: integer AS codigo, counco, zutm, dathor, geom FROM midagri.comunidad_campesina) as sbn using unique gid using srid=4326"
    FILTER ("[depar]" IN "CUSCO")
	INCLUDE "configuracion/postgresql_allpa.map"
	PROJECTION
	"init=epsg:4326"
	END
	METADATA
		"layer_encoding" "Latin1"
		"wfs_encoding" "Latin1"
		"queryable" "true"		
		"wfs_title" "Comunidad Campesina"
		"wfs_abstract" "Comunidad Campesina || Ministerio de Desarrollo Agrario y Rural - MIDAGRI"
		"wfs_srs" "EPSG:4326"
		"gml_include_items" "all"
		"gml_featureid" "gid"
		"wfs_enable_request" "*"
		"wfs_getfeature_formatlist" "geojson,application/geojson,application/geo+json,application/json,gml,csv,SHAPE-ZIP" 
		#"wfs_additional_files_in_output" "anp_administracion_nacional.pdf,anp_administracion_nacional.lyr"
	END
	CLASS
		NAME "Comunidad campesina"
		STYLE
			COLOR 28 28 28
			OUTLINECOLOR 128 128 128
			WIDTH 1
		END
	END
END # Layer